  1: // WORKSTATE handoff integrity harness.
  2: // Checks that the current handoff record is backed by real files, hashes, and completion artifacts.
  3: // --workstate + --applier-log 둘 다 지정 시 fixture 격리 모드: reconciliation+malformed+blockers만 실행.
  4: using System.Security.Cryptography;
  5: using System.Text.Encodings.Web;
  6: using System.Text.Json;
  7: using System.Text.Json.Nodes;
  8: 
  9: internal static class HandoffIntegrityCli
 10: {
 11:     private static readonly JsonSerializerOptions JsonOptions = new()
 12:     {
 13:         WriteIndented = true,
 14:         Encoder = JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
 15:     };
 16: 
 17:     private static readonly HashSet<string> DoneStatuses = new(StringComparer.OrdinalIgnoreCase)
 18:     {
 19:         "done", "completed", "complete", "pass", "passed",
 20:     };
 21: 
 22:     // handoff-integrity entry. exit 0=integrity verified, 1=contract gap, 2=harness error.
 23:     internal static int Run(string[] args)
 24:     {
 25:         try
 26:         {
 27:             if (args.Any(a => string.Equals(a, "--pending-transition", StringComparison.OrdinalIgnoreCase)))
 28:             {
 29:                 Console.Error.WriteLine("{\"error\":\"pending-not-allowed-on-cli\",\"code\":\"pending-not-allowed-on-cli\"}");
 30:                 return 1;
 31:             }
 32:             var root = GitTools.FindRepoRoot();
 33:             if (args.Any(a => string.Equals(a, "--self-test", StringComparison.OrdinalIgnoreCase)))
 34:                 return RunSelfTest(root);
 35:             var (workstatePath, applierLogPath, fixtureMode) = ParsePaths(args, root);
 36:             if (!File.Exists(workstatePath))
 37:                 { Console.Error.WriteLine("{\"error\":\"WORKSTATE.json not found\"}"); return 2; }
 38:             var parsed = JsonNode.Parse(File.ReadAllText(workstatePath)) as JsonObject;
 39:             if (parsed is null)
 40:                 { Console.Error.WriteLine("{\"error\":\"WORKSTATE.json is not a JSON object\"}"); return 2; }
 41:             return RunChecks(root, parsed, workstatePath, applierLogPath, fixtureMode);
 42:         }
 43:         catch (Exception ex)
 44:         {
 45:             Console.Error.WriteLine($"{{\"error\":\"handoff-integrity failed: {ex.Message}\"}}");
 46:             return 2;
 47:         }
 48:     }
 49: 
 50:     // --workstate / --applier-log 인자를 파싱해 절대 경로와 모드를 반환한다.
 51:     private static (string workstatePath, string applierLogPath, bool fixtureMode) ParsePaths(string[] args, string root)
 52:     {
 53:         string? workstateArg = null;
 54:         string? applierLogArg = null;
 55:         for (int i = 1; i < args.Length; i++)
 56:         {
 57:             if (string.Equals(args[i], "--workstate", StringComparison.OrdinalIgnoreCase) && i + 1 < args.Length)
 58:                 workstateArg = args[++i];
 59:             else if (string.Equals(args[i], "--applier-log", StringComparison.OrdinalIgnoreCase) && i + 1 < args.Length)
 60:                 applierLogArg = args[++i];
 61:             else if (workstateArg is null && !args[i].StartsWith("--"))
 62:                 workstateArg = args[i];
 63:         }
 64:         var wsPath = workstateArg is not null
 65:             ? Path.GetFullPath(Path.IsPathRooted(workstateArg) ? workstateArg : Path.Combine(root, workstateArg))
 66:             : Path.Combine(root, "docs", "handoff", "WORKSTATE.json");
 67:         var logPath = applierLogArg is not null
 68:             ? Path.GetFullPath(Path.IsPathRooted(applierLogArg) ? applierLogArg : Path.Combine(root, applierLogArg))
 69:             : Path.Combine(root, "docs", "handoff", "WORKSTATE.applier-log.jsonl");
 70:         return (wsPath, logPath, applierLogArg is not null);
 71:     }
 72: 
 73:     // 모든 검사를 실행하고 보고서를 출력한다.
 74:     private static int RunChecks(
 75:         string root, JsonObject parsed, string workstatePath, string applierLogPath, bool fixtureMode)
 76:     {
 77:         var failures = new JsonArray();
 78:         var warnings = new JsonArray();
 79:         var changedFiles = new JsonArray();
 80:         var diId = ReadString(parsed, "diId");
 81:         var status = ReadString(parsed, "status");
 82: 
 83:         var reconc = RunReconciliation(workstatePath, applierLogPath, failures, warnings);
 84:         if (reconc.harnessErrors > 0)
 85:         {
 86:             Console.WriteLine(new JsonObject
 87:             {
 88:                 ["harness"] = "handoff-integrity",
 89:                 ["workstate"] = Path.GetRelativePath(root, workstatePath).Replace('\\', '/'),
 90:                 ["fixtureMode"] = fixtureMode,
 91:                 ["verdict"] = "HARNESS_ERROR",
 92:                 ["failures"] = failures, ["warnings"] = warnings,
 93:             }.ToJsonString(JsonOptions));
 94:             return 2;
 95:         }
 96: 
 97:         if (!fixtureMode)
 98:             RunFullModeChecks(root, parsed, diId, status, failures, warnings, changedFiles);
 99:         CheckBlockerConsistency(parsed, status, failures);
100: 
101:         Console.WriteLine(new JsonObject
102:         {
103:             ["harness"] = "handoff-integrity",
104:             ["workstate"] = Path.GetRelativePath(root, workstatePath).Replace('\\', '/'),
105:             ["applierLog"] = Path.GetRelativePath(root, applierLogPath).Replace('\\', '/'),
106:             ["fixtureMode"] = fixtureMode,
107:             ["diId"] = diId, ["status"] = status,
108:             ["changedFileCount"] = changedFiles.Count,
109:             ["failureCount"] = failures.Count, ["warningCount"] = warnings.Count,
110:             ["verdict"] = failures.Count == 0 ? "PASS" : "FAIL",
111:             ["reconciliation"] = reconc.reconciliationResult,
112:             ["changedFiles"] = changedFiles, ["failures"] = failures, ["warnings"] = warnings,
113:             ["note"] = fixtureMode
114:                 ? "Fixture isolation mode: reconciliation+blockers only."
115:                 : "Full mode: changedFiles hash, completion, queue, reconciliation.",
116:         }.ToJsonString(JsonOptions));
117:         return failures.Count == 0 ? 0 : 1;
118:     }
119: 
120:     // full 모드에서 changedFiles·completion·queue를 검사한다.
121:     private static void RunFullModeChecks(
122:         string root, JsonObject parsed, string diId, string status,
123:         JsonArray failures, JsonArray warnings, JsonArray changedFiles)
124:     {
125:         CheckRequired(parsed, "schemaVersion", failures);
126:         CheckRequired(parsed, "diId", failures);
127:         CheckRequired(parsed, "status", failures);
128:         var changed = parsed["changedFiles"] as JsonArray;
129:         if (changed is null || changed.Count == 0)
130:             failures.Add(Failure("changedFiles", "missing", "changedFiles must be a non-empty array"));
131:         else
132:             foreach (var item in changed.OfType<JsonObject>())
133:                 changedFiles.Add(CheckChangedFile(root, item, failures));
134:         CheckCompletionArtifacts(root, parsed, diId, status, failures, warnings);
135:         CheckQueueStatus(root, diId, status, failures, warnings);
136:     }
137: 
138:     // HandoffIntegrityChecker를 실행하고 결과를 failures/warnings에 병합한다.
139:     private static (int harnessErrors, JsonNode? reconciliationResult) RunReconciliation(
140:         string workstatePath, string applierLogPath,
141:         JsonArray failures, JsonArray warnings)
142:     {
143:         var opts = new ReconciliationOptions(workstatePath, applierLogPath, null);
144:         var result = HandoffIntegrityChecker.Run(opts);
145: 
146:         foreach (var e in result.HarnessErrors)
147:             Console.Error.WriteLine($"{{\"harness-error\":\"{e.Code}\",\"subject\":\"{e.Subject}\",\"message\":\"{e.Message}\"}}");
148: 
149:         if (result.HarnessErrors.Count > 0)
150:             return (result.HarnessErrors.Count, null);
151: 
152:         foreach (var f in result.Failures)
153:             failures.Add(Failure(f.Subject, f.Code, f.Message));
154:         foreach (var w in result.Warnings)
155:             warnings.Add(Warning(w.Subject, w.Code, w.Message));
156: 
157:         JsonNode? metricsNode = null;
158:         if (result.Metrics is { } m)
159:         {
160:             metricsNode = new JsonObject
161:             {
162:                 ["appliedTransitionCount"] = m.AppliedTransitionCount,
163:                 ["successfulLogEntryCount"] = m.SuccessfulLogEntryCount,
164:                 ["successfulLogIdCount"] = m.SuccessfulLogIdCount,
165:                 ["duplicateSuccessLogCount"] = m.DuplicateSuccessLogCount,
166:                 ["pendingExemptionApplied"] = m.PendingExemptionApplied,
167:                 ["reconciliation"] = m.Reconciliation,
168:             };
169:         }
170: 
171:         return (0, metricsNode);
172:     }
173: 
174:     // 필수 최상위 WORKSTATE 필드를 확인한다.
175:     private static void CheckRequired(JsonObject root, string property, JsonArray failures)
176:     {
177:         if (root[property] is null || string.IsNullOrWhiteSpace(root[property]?.ToString()))
178:             failures.Add(Failure($"workstate.{property}", "missing", "required field is absent or empty"));
179:     }
180: 
181:     // changedFiles 항목 하나를 파일시스템·해시와 대조한다.
182:     private static JsonObject CheckChangedFile(string root, JsonObject item, JsonArray failures)
183:     {
184:         var path = ReadString(item, "path");
185:         var entry = new JsonObject
186:         {
187:             ["path"] = path,
188:             ["exists"] = false,
189:             ["hashField"] = "",
190:             ["hashMatches"] = null,
191:         };
192: 
193:         if (string.IsNullOrWhiteSpace(path))
194:         {
195:             failures.Add(Failure("changedFiles.path", "missing", "changedFiles item has no path"));
196:             return entry;
197:         }
198: 
199:         var full = Path.GetFullPath(Path.Combine(root, path));
200:         var insideRoot = full.Equals(root, StringComparison.OrdinalIgnoreCase)
201:             || full.StartsWith(root.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar)
202:                 + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase);
203:         if (!insideRoot)
204:         {
205:             failures.Add(Failure(path, "outside-root", "changedFiles path escapes repository root"));
206:             return entry;
207:         }
208: 
209:         var exists = File.Exists(full) || Directory.Exists(full);
210:         entry["exists"] = exists;
211:         if (!exists)
212:         {
213:             failures.Add(Failure(path, "missing-file", "changedFiles path does not exist"));
214:             return entry;
215:         }
216: 
217:         var expectedHash = ReadString(item, "sha256");
218:         var hashField = "sha256";
219:         if (string.IsNullOrWhiteSpace(expectedHash))
220:         {
221:             expectedHash = ReadString(item, "hash");
222:             hashField = "hash";
223:         }
224: 
225:         entry["hashField"] = string.IsNullOrWhiteSpace(expectedHash) ? "" : hashField;
226:         if (string.IsNullOrWhiteSpace(expectedHash))
227:         {
228:             failures.Add(Failure(path, "missing-hash", "changedFiles item lacks sha256/hash"));
229:             return entry;
230:         }
231: 
232:         if (Directory.Exists(full))
233:         {
234:             failures.Add(Failure(path, "directory-hash-unsupported", "changedFiles hash can only be verified for files"));
235:             return entry;
236:         }
237: 
238:         var actualHash = Convert.ToHexString(SHA256.HashData(File.ReadAllBytes(full))).ToLowerInvariant();
239:         var normalizedExpected = expectedHash.Trim().ToLowerInvariant().Replace("sha256:", "");
240:         var matches = actualHash.Equals(normalizedExpected, StringComparison.OrdinalIgnoreCase);
241:         entry["actualSha256"] = actualHash;
242:         entry["hashMatches"] = matches;
243:         if (!matches)
244:             failures.Add(Failure(path, "hash-mismatch", "changedFiles hash does not match current file content"));
245: 
246:         return entry;
247:     }
248: 
249:     // 완료 상태의 handoff가 실제 verification 아티팩트를 가리키는지 확인한다.
250:     private static void CheckCompletionArtifacts(string root, JsonObject workstate, string diId, string status, JsonArray failures, JsonArray warnings)
251:     {
252:         if (!DoneStatuses.Contains(status)) return;
253: 
254:         var changed = workstate["changedFiles"] as JsonArray;
255:         var verificationInChangedFiles = changed?.OfType<JsonObject>()
256:             .Select(o => ReadString(o, "path"))
257:             .Any(p => p.StartsWith("docs/verification/", StringComparison.OrdinalIgnoreCase)
258:                 && File.Exists(Path.Combine(root, p))) == true;
259: 
260:         var verificationById = false;
261:         var verificationDir = Path.Combine(root, "docs", "verification");
262:         if (!verificationInChangedFiles && Directory.Exists(verificationDir) && !string.IsNullOrWhiteSpace(diId))
263:         {
264:             var normalized = NormalizeId(diId);
265:             verificationById = Directory.EnumerateFiles(verificationDir, "*.md")
266:                 .Any(path => NormalizeId(Path.GetFileNameWithoutExtension(path)).Contains(normalized));
267:         }
268: 
269:         if (!verificationInChangedFiles && !verificationById)
270:             failures.Add(Failure(diId, "missing-verification", "done status requires an existing docs/verification artifact"));
271:         else if (!verificationInChangedFiles)
272:             warnings.Add(Warning(diId, "verification-not-in-changedFiles", "verification exists by id but is not listed in current changedFiles"));
273:     }
274: 
275:     // WORKSTATE diId가 큐 파일에서 열린 상태인지 대조한다.
276:     private static void CheckQueueStatus(string root, string diId, string status, JsonArray failures, JsonArray warnings)
277:     {
278:         if (string.IsNullOrWhiteSpace(diId)) return;
279: 
280:         var queueFiles = new[]
281:         {
282:             "docs/handoff/CODEX-QUEUE.md",
283:             "docs/handoff/SONNET-QUEUE.md",
284:         };
285:         var mentions = new JsonArray();
286:         foreach (var rel in queueFiles)
287:         {
288:             var full = Path.Combine(root, rel);
289:             if (!File.Exists(full)) continue;
290:             foreach (var line in File.ReadLines(full).Where(l => l.Contains(diId, StringComparison.OrdinalIgnoreCase)))
291:             {
292:                 mentions.Add(new JsonObject
293:                 {
294:                     ["queue"] = rel,
295:                     ["line"] = line.Trim(),
296:                 });
297:                 if (DoneStatuses.Contains(status) && IsOpenQueueLine(line))
298:                     failures.Add(Failure(rel, "queue-status-mismatch", $"{diId} is done in WORKSTATE but open in queue line"));
299:             }
300:         }
301: 
302:         if (mentions.Count == 0)
303:             warnings.Add(Warning(diId, "queue-mention-missing", "diId is not mentioned in CODEX or SONNET queue"));
304:     }
305: 
306:     // blocked 상태에 blockers[]가 없거나 비어 있으면 blockers-missing, done 상태에 blockers[]가 남으면 blockers-stale.
307:     private static void CheckBlockerConsistency(JsonObject workstate, string status, JsonArray failures)
308:     {
309:         var blockers = workstate["blockers"] as JsonArray;
310:         var hasBlockers = blockers is not null && blockers.Count > 0;
311:         var blocked = status.Contains("block", StringComparison.OrdinalIgnoreCase);
312:         if (blocked && !hasBlockers)
313:             failures.Add(Failure("blockers", "blockers-missing", "blocked status requires a non-empty blockers array"));
314:         if (!blocked && hasBlockers && DoneStatuses.Contains(status))
315:             failures.Add(Failure("blockers", "blockers-stale", "done status must not carry a non-empty blockers array"));
316:     }
317: 
318:     // 큐 행이 아직 열린 상태를 뜻하는지 판정한다.
319:     private static bool IsOpenQueueLine(string line)
320:         => line.Contains("대기", StringComparison.Ordinal)
321:             || line.Contains("진행", StringComparison.Ordinal)
322:             || line.Contains("pending", StringComparison.OrdinalIgnoreCase)
323:             || line.Contains("in progress", StringComparison.OrdinalIgnoreCase);
324: 
325:     // JSON 객체에서 문자열 속성을 안전하게 읽는다.
326:     private static string ReadString(JsonObject obj, string property)
327:         => obj[property]?.ToString() ?? "";
328: 
329:     // 지시서 ID와 파일명을 비교하기 쉬운 영숫자 소문자로 정규화한다.
330:     private static string NormalizeId(string value)
331:         => new string(value.Where(char.IsLetterOrDigit).Select(char.ToLowerInvariant).ToArray());
332: 
333:     // 실패 항목을 공통 JSON 형식으로 만든다.
334:     private static JsonObject Failure(string subject, string code, string message)
335:         => new() { ["subject"] = subject, ["code"] = code, ["message"] = message };
336: 
337:     // 경고 항목을 공통 JSON 형식으로 만든다.
338:     private static JsonObject Warning(string subject, string code, string message)
