268:     // 06C-1 idempotency 판정을 위한 lookupSuccess 사전을 채운다.
269:     private static void BuildLookup(
270:         HashSet<string> successfulLogIdSet,
271:         Dictionary<string, List<LogEntry>> successCounts,
272:         ReconciliationResult result)
273:     {
274:         foreach (var id in successfulLogIdSet)
