282:     // 지표 객체를 조립한다.
283:     private static ReconciliationMetrics BuildMetrics(
284:         List<string> stateIds, List<LogEntry> logEntries,
285:         (HashSet<string> stateIdSet, HashSet<string> successfulLogIdSet,
286:          HashSet<string> allLogIdSet, Dictionary<string, List<LogEntry>> successCounts) sets,
287:         bool pendingApplied, ReconciliationResult result)
288:     {
289:         var successfulEntries = logEntries
290:             .Where(e => string.Equals(e.Result, "ok", StringComparison.OrdinalIgnoreCase) && e.ExitCode == 0)
291:             .ToList();
292:         var schemaVersions = logEntries
293:             .GroupBy(e => $"v{e.SchemaVersion}")
294:             .ToDictionary(g => g.Key, g => g.Count());
295:         var dupCount = sets.successCounts.Values.Count(v => v.Count > 1);
296:         var allClear = result.Failures.Count == 0 && result.HarnessErrors.Count == 0;
297:         return new ReconciliationMetrics(
298:             AppliedTransitionCount: stateIds.Count,
299:             SuccessfulLogEntryCount: successfulEntries.Count,
300:             SuccessfulLogIdCount: sets.successfulLogIdSet.Count,
301:             DuplicateSuccessLogCount: dupCount,
302:             LogSchemaVersions: schemaVersions,
303:             PendingExemptionApplied: pendingApplied,
304:             Reconciliation: allClear ? "PASS" : "FAIL"
305:         );
306:     }
