308:     // v2 log 항목의 필수 필드를 검증한다. 오류 메시지를 반환하고 정상이면 null.
309:     private static string? ValidateV2Fields(JsonObject row, string tid)
310:     {
311:         var kind = row["transitionKind"]?.GetValue<string>() ?? "";
312:         if (!AllowedTransitionKinds.Contains(kind))
313:             return $"transitionKind missing or invalid (got '{kind}')";
314: 
315:         foreach (var field in new[] { "requestSha256", "preStateSha256", "postStateSha256", "transitionContractSha256" })
316:         {
317:             var val = row[field]?.GetValue<string>() ?? "";
318:             if (!Is64Hex(val)) return $"{field} missing or not 64-char hex";
319:         }
320: 
321:         var effectiveAt = row["effectiveAt"]?.GetValue<string>() ?? "";
322:         if (!IsValidUtcRfc3339(effectiveAt)) return $"effectiveAt invalid: '{effectiveAt}'";
323:         return null;
324:     }
