326:     // 64자 16진수 문자열인지 확인한다.
327:     private static bool Is64Hex(string? s)
328:         => s is { Length: 64 } && s.All(c =>
329:             (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F'));
