331:     // UTC RFC3339 타임스탬프 형식인지 확인한다.
332:     private static bool IsValidUtcRfc3339(string? s)
333:     {
334:         if (string.IsNullOrWhiteSpace(s)) return false;
335:         return DateTimeOffset.TryParse(s,
336:             System.Globalization.CultureInfo.InvariantCulture,
337:             System.Globalization.DateTimeStyles.RoundtripKind, out _);
338:     }
